import React from "react";

const BarraHorizontal = ({
  texto,
  height = "10vh",
  margenHorizontal = "10vw",
  imagen,
}) => {
  // Las propiedades dinámicas como la imagen de fondo, el alto del contenedor
  // y el ancho de las barras laterales se manejan con objetos de estilo.
  // Esta es la práctica recomendada cuando se trabaja con valores que vienen de props.
  const containerStyle = { height };

  const imageStyle = {
    backgroundImage: `url(${imagen})`,
    width: margenHorizontal,
  };

  return (
    <div 
      style={containerStyle} 
      className="w-full flex items-center overflow-hidden bg-gradient-to-r from-surface-elevated via-surface to-surface-elevated border-y-2 border-gradient-to-r from-primary/20 via-primary to-primary/20 shadow-lg relative"
    >
      {/* Elementos decorativos modernos */}
      <div className="absolute top-0 left-0 w-full h-0.5 bg-gradient-to-r from-transparent via-primary-light to-transparent"></div>
      <div className="absolute bottom-0 left-0 w-full h-0.5 bg-gradient-to-r from-transparent via-accent to-transparent"></div>
      
      <div
        style={imageStyle}
        // Clases de Tailwind para el estilo y repetición de la imagen con mejor integración
        className="bg-repeat-x bg-center h-[60%] flex-shrink-0 bg-[length:auto_100%] opacity-60"
      />
      <div
        // APLICACIÓN DE LA NUEVA PALETA Y TIPOGRAFÍA MODERNA:
        // Usamos font-bodoni para títulos, text-primary para el color principal
        // y agregamos efectos visuales más elegantes con gradientes
        className="flex-grow h-full flex items-center justify-center font-bodoni text-transparent bg-clip-text bg-gradient-to-r from-primary via-primary-light to-accent text-xl tracking-[0.35em] transform -translate-y-[2%] font-bold uppercase relative"
      >
        {/* Sombra de texto para mayor impacto */}
        <span className="absolute inset-0 text-primary/20 blur-sm">{texto}</span>
        <span className="relative">{texto}</span>
      </div>
      <div
        style={imageStyle}
        className="bg-repeat-x bg-center h-[60%] flex-shrink-0 bg-[length:auto_100%] opacity-60"
      />
    </div>
  );
};

export default BarraHorizontal;
